// The synthetic ensures is `BIG_CONJ ==> det_kill_blocked_thread_equal(...)`
// — the original function's ensures clauses for r1/post1 and r2/post2 are
// the LHS of the implication, NOT hypotheses in the proof body. The prior
// attempt asserted them unconditionally and Verus rejected those asserts.
//
// Fix: wrap the proof in `if BIG_CONJ { ... }` so the conjuncts become real
// hypotheses, then assert the cross-side equalities so z3 can collapse
// post1_self_ and post2_self_ on the trace where the postcondition matters.

if ({
    &&& post1_self_.wf()
    &&& post1_self_.thread_dom() == pre_self_.thread_dom().remove(thread_ptr)
    &&& threads_unchanged_except(pre_self_, post1_self_, set![])
    &&& post1_self_.proc_dom() == pre_self_.proc_dom()
    &&& process_tree_unchanged(pre_self_, post1_self_)
    &&& post1_self_.container_dom() == pre_self_.container_dom()
    &&& containers_tree_unchanged(pre_self_, post1_self_)
    &&& post1_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@ ==
        pre_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@.remove_value(thread_ptr)
    &&& post1_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len() ==
        pre_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len() - 1
    &&& process_mem_unchanged(pre_self_, post1_self_)
    &&& (r1.1.is_Some() ==> {
        &&& post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.0.0).remove(r1.1.unwrap().0)
        &&& pre_self_.page_closure().contains(r1.0.0)
        &&& r1.0.0 == r1.0.1@.addr()
        &&& r1.0.1@.is_init()
        &&& pre_self_.container_dom().contains(r1.0.0) == false
        &&& pre_self_.page_closure().contains(r1.1.unwrap().0)
        &&& r1.1.unwrap().0 == r1.1.unwrap().1@.addr()
        &&& r1.1.unwrap().1@.is_init()
        &&& pre_self_.container_dom().contains(r1.1.unwrap().0) == false
        &&& r1.0.0 != r1.1.unwrap().0
    })
    &&& (r1.1.is_None() ==> {
        &&& post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.0.0)
        &&& pre_self_.page_closure().contains(r1.0.0)
        &&& r1.0.0 == r1.0.1@.addr()
        &&& r1.0.1@.is_init()
        &&& pre_self_.container_dom().contains(r1.0.0) == false
    })
    &&& post2_self_.wf()
    &&& post2_self_.thread_dom() == pre_self_.thread_dom().remove(thread_ptr)
    &&& threads_unchanged_except(pre_self_, post2_self_, set![])
    &&& post2_self_.proc_dom() == pre_self_.proc_dom()
    &&& process_tree_unchanged(pre_self_, post2_self_)
    &&& post2_self_.container_dom() == pre_self_.container_dom()
    &&& containers_tree_unchanged(pre_self_, post2_self_)
    &&& post2_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@ ==
        pre_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@.remove_value(thread_ptr)
    &&& post2_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len() ==
        pre_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len() - 1
    &&& process_mem_unchanged(pre_self_, post2_self_)
    &&& (r2.1.is_Some() ==> {
        &&& post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.0.0).remove(r2.1.unwrap().0)
        &&& pre_self_.page_closure().contains(r2.0.0)
        &&& r2.0.0 == r2.0.1@.addr()
        &&& r2.0.1@.is_init()
        &&& pre_self_.container_dom().contains(r2.0.0) == false
        &&& pre_self_.page_closure().contains(r2.1.unwrap().0)
        &&& r2.1.unwrap().0 == r2.1.unwrap().1@.addr()
        &&& r2.1.unwrap().1@.is_init()
        &&& pre_self_.container_dom().contains(r2.1.unwrap().0) == false
        &&& r2.0.0 != r2.1.unwrap().0
    })
    &&& (r2.1.is_None() ==> {
        &&& post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.0.0)
        &&& pre_self_.page_closure().contains(r2.0.0)
        &&& r2.0.0 == r2.0.1@.addr()
        &&& r2.0.1@.is_init()
        &&& pre_self_.container_dom().contains(r2.0.0) == false
    })
}) {
    // Both runs land on the same set-valued domains.
    assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());
    assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
    assert(post1_self_.container_dom() =~= post2_self_.container_dom());

    // Owned-threads sequence and length collapse via the shared `remove_value` spec.
    assert(post1_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@
        =~= post2_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@);
    assert(post1_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len()
        == post2_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len());

    // Tuple-level address equalities tying PagePtr to its tracked-perm view.
    assert(r1.0.0 == r1.0.1@.addr());
    assert(r2.0.0 == r2.0.1@.addr());

    // Conditional facts for the Some/None split — pull each branch's
    // ensures into the proof context so z3 can line up r1 and r2 cases.
    if r1.1.is_Some() {
        assert(post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.0.0).remove(r1.1.unwrap().0));
        assert(pre_self_.page_closure().contains(r1.0.0));
        assert(pre_self_.page_closure().contains(r1.1.unwrap().0));
        assert(r1.1.unwrap().0 == r1.1.unwrap().1@.addr());
        assert(r1.1.unwrap().1@.is_init());
        assert(r1.0.0 != r1.1.unwrap().0);
    } else {
        assert(r1.1.is_None());
        assert(post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.0.0));
        assert(pre_self_.page_closure().contains(r1.0.0));
        assert(r1.0.1@.is_init());
    }

    if r2.1.is_Some() {
        assert(post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.0.0).remove(r2.1.unwrap().0));
        assert(pre_self_.page_closure().contains(r2.0.0));
        assert(pre_self_.page_closure().contains(r2.1.unwrap().0));
        assert(r2.1.unwrap().0 == r2.1.unwrap().1@.addr());
        assert(r2.1.unwrap().1@.is_init());
        assert(r2.0.0 != r2.1.unwrap().0);
    } else {
        assert(r2.1.is_None());
        assert(post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.0.0));
        assert(pre_self_.page_closure().contains(r2.0.0));
        assert(r2.0.1@.is_init());
    }
}
